-- 1. CLEANUP (Prevents "Duplicate Entry" errors on restart)
-- We disable referential integrity so we can truncate tables with foreign keys.
SET REFERENTIAL_INTEGRITY FALSE;
TRUNCATE TABLE result;
TRUNCATE TABLE question;
TRUNCATE TABLE quiz;
TRUNCATE TABLE student;
TRUNCATE TABLE teacher;
SET REFERENTIAL_INTEGRITY TRUE;

-- 2. INSERT TEACHER
-- Note: 'id' is auto-generated by Hibernate, so we don't include it here.
INSERT INTO teacher (name, tchrid, password)
VALUES ('ak', '1', 'ak');

-- 3. INSERT STUDENT
INSERT INTO student (name, roll_no, password)
VALUES ('vv', '1', 'ak');

-- 4. INSERT INITIAL QUIZ (So the dashboard isn't empty)
-- We manually set ID 1 here so we can link questions to it.
INSERT INTO quiz (id, title)
VALUES (1, 'Java OOP & Basics');

-- FIX: After manually inserting quiz id=1, advance H2's sequence counter so
-- Hibernate's @GeneratedValue(IDENTITY) starts at 2 for the next quiz.
-- Without this, publishing a new quiz throws a Unique constraint violation on id.
ALTER TABLE quiz ALTER COLUMN id RESTART WITH 2;

-- 5. INSERT SAMPLE QUESTIONS
-- correct_option: 0=A(option1), 1=B(option2), 2=C(option3), 3=D(option4)
INSERT INTO question (question_text, option1, option2, option3, option4, correct_option, marks, quiz_id)
VALUES ('Which keyword is used to inherit a class in Java?',
        'implements', 'extends', 'inherits', 'super',
        1, 1, 1); -- Answer: B (extends)

INSERT INTO question (question_text, option1, option2, option3, option4, correct_option, marks, quiz_id)
VALUES ('Which of these is NOT a pillar of OOP?',
        'Encapsulation', 'Abstraction', 'Inheritance', 'Compilation',
        3, 1, 1); -- Answer: D (Compilation)

INSERT INTO question (question_text, option1, option2, option3, option4, correct_option, marks, quiz_id)
VALUES ('What is the default value of an int variable in Java?',
        '1', 'null', '0', '-1',
        2, 1, 1); -- Answer: C (0)

